SELECT b.id, b.category_id, b.title, b.writer, b.content, b.view_count, b.created_at, b.updated_at, EXISTS (SELECT 1 FROM files f WHERE f.board_id = b.id) AS has_attachment FROM board b
AND b.category_id = #{condition.categoryId}
AND ( b.title LIKE CONCAT('%', #{condition.keyword}, '%') OR b.writer LIKE CONCAT('%', #{condition.keyword}, '%') OR b.content LIKE CONCAT('%', #{condition.keyword}, '%') )
AND b.created_at >= #{condition.startDate}
AND b.created_at < DATE_ADD(#{condition.endDate}, INTERVAL 1 DAY)
ORDER BY b.created_at DESC, b.id DESC LIMIT #{condition.size} OFFSET #{offset}

SELECT COUNT(*)
FROM board b


    AND b.category_id = #{condition.categoryId}


    AND (
    b.title LIKE CONCAT('%', #{condition.keyword}, '%')
    OR b.writer LIKE CONCAT('%', #{condition.keyword}, '%')
    OR b.content LIKE CONCAT('%', #{condition.keyword}, '%')
    )


    AND b.created_at >= #{condition.startDate}


    AND b.created_at < DATE_ADD(#{condition.endDate}, INTERVAL 1 DAY)

